Pattern: Allocation in Loop vs Sliding Window

Optimize this code to eliminate the inefficiency. Rename the function to `optimized`.
Return ONLY the optimized C function.

```c
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>

__attribute__((noinline))
double slow_mi1_v010(double *input, int n, int win) {
    double total = 0.0;
    for (int i = 0; i <= n - win; i++) {
        double *buf = malloc(win * sizeof(double));
        for (int j = 0; j < win; j++) buf[j] = input[i + j];
        double sum = 0.0;
        for (int j = 0; j < win; j++) sum += buf[j];
        total += sum / win;
        free(buf);
    }
    return total;
}
```

```c
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>

__attribute__((noinline))
double optimized(double *input, int n, int win) {
    double total = 0.0, sum = 0.0;
    for (int j = 0; j < win; j++) sum += input[j];
    total += sum / win;
    for (int i = 1; i <= n - win; i++) {
        sum += input[i + win - 1] - input[i - 1];
        total += sum / win;
    }
    return total;
}
